def is_felony(assault_type, has_weapon=False, bodily_injury=False):
    if assault_type == "simple assault":
        return False
    elif assault_type == "physical contact":
        return True  # Class D felony
    elif has_weapon or bodily_injury:
        return True  # Class C felony
    return False

# Example usage:
print(is_felony("simple assault"))  # False
print(is_felony("physical contact"))  # True
print(is_felony("simple assault", has_weapon=True))  # True
